CREATE OR REPLACE FUNCTION fpa_com_fee_bank_marine (as_bank_id char , as_branch_bank char , adc_balance bigint) RETURNS bigint AS $body$
DECLARE

ldc_fee bigint;

BEGIN

  case trim(both as_bank_id)
    when '11' then
      if trim(both as_branch_bank) in ('302','418') then  --ถ้าเป็น ธ.ทหารไทย สาขา สัตหีบ คิดค่า ธ/น 10 บาท
         ldc_fee := 10;return ldc_fee;
      else
        goto Fee_else;
      end if;
    when '06' then  --ธ. กรุงไทย
      if trim(both as_branch_bank) in ('230','232') then  -- สาขา พลูตาหลวง กับ สัตหีบ
        ldc_fee := 15;return ldc_fee;
      else
         goto Fee_else;
      end if;
    else
        goto Fee_else;
  end case;
  --ถ้าเป็นสาขาอื่นคิดจากยอดเงิน 10,000 ละ 10 บาท รวมกับค่าธรรรมเนียมอีก 20 บาท โดยปัดเศษขึ้นหมด
  <<Fee_else>>
    if adc_balance <= 10000 then
    ldc_fee := 10 + 20; -- หนึ่งหมื่นบาทแรก คิด 10 บาทเลยคับ รวมกับค่า โอน 20 บาท
    else
    ldc_fee := PKA_LON_INTSRV.fp_round_decimal((adc_balance * 0.001),1,'+') + 20;
    end if;
    return ldc_fee;
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
